/* Coached by Dukkha */
#include <stdio.h>

int same(int a, int b, int c, int d) {
	return a == b && b == c && c == d;
}

int check(int a13, int a14, int a5, int a6, int a17, int a18, int a21, int a22,
		int a15, int a16, int a7, int a8, int a19, int a20, int a23, int a24) {
	return same(a15, a16, a5, a6) && same(a7, a8, a17, a18) && same(a19, a20, a21, a22) && same(a23, a24, a13, a14)
		|| same(a13, a14, a7, a8) && same(a5, a6, a19, a20) && same(a17, a18, a23, a24) && same(a21, a22, a15, a16);
}

int main() {
	int a1, a2, a3, a4,
	a5, a6, a7, a8,
	a9, a10, a11, a12,
	a13, a14, a15, a16,
	a17, a18, a19, a20,
	a21, a22, a23, a24;

	scanf("%d%d%d%d", &a1, &a2, &a3, &a4);
	scanf("%d%d%d%d", &a5, &a6, &a7, &a8);
	scanf("%d%d%d%d", &a9, &a10, &a11, &a12);
	scanf("%d%d%d%d", &a13, &a14, &a15, &a16);
	scanf("%d%d%d%d", &a17, &a18, &a19, &a20);
	scanf("%d%d%d%d", &a21, &a22, &a23, &a24);
	if (same(a1, a2, a3, a4) && same(a9, a10, a11, a12) && check(
				a13, a14, a5, a6, a17, a18, a21, a22,
				a15, a16, a7, a8, a19, a20, a23, a24)) {
		printf("YES\n");
		return 0;
	}
	if (same(a5, a6, a7, a8) && same(a21, a22, a23, a24) && check(
				a9, a10, a19, a17, a4, a3, a14, a16,
				a11, a12, a20, a18, a2, a1, a13, a15)) {
		printf("YES\n");
		return 0;
	}
	if (same(a13, a14, a15, a16) && same(a17, a18, a19, a20) && check(
				a11, a9, a7, a5, a3, a1, a22, a24,
				a12, a10, a8, a6, a4, a2, a21, a23)) {
		printf("YES\n");
		return 0;
	}
	printf("NO\n");
	return 0;
}

